ASN1C_CoreCPID::ASN1C_CoreCPID (ASN1T_CoreCPID& data) : 
   ASN1CType(), msgData(data)
{
   setRunTimeKey (_rtkey, sizeof(_rtkey));
}

ASN1C_CoreCPID::ASN1C_CoreCPID (OSRTMessageBufferIF& msgBuf
   , ASN1T_CoreCPID& data) : ASN1CType(msgBuf), msgData(data)
{
   setRunTimeKey (_rtkey, sizeof(_rtkey));
}
ASN1C_CoreCPID::ASN1C_CoreCPID (OSRTContext &context, ASN1T_CoreCPID& data) : 
   ASN1CType(context), msgData(data)
{
   setRunTimeKey (_rtkey, sizeof(_rtkey));
}


ASN1T_CoreCPID::~ASN1T_CoreCPID ()
{
   OSCTXT* pctxt = mpContext.getCtxtPtr();
   if (pctxt != 0 && !rtxMemHeapIsEmpty (pctxt)) {
      asn1Free_CoreCPID (pctxt, this);
   }
}

int ASN1C_CoreCPID::EncodeTo (OSRTMessageBufferIF& msgBuf)
{
   int stat = setMsgBuf (msgBuf, TRUE);
   if (stat != 0) return (stat);

   if (msgBuf.isA (OSRTMessageBufferIF::PEREncode)) {
      stat= asn1PE_CoreCPID (msgBuf.getCtxtPtr(), &msgData);
      ((ASN1PEREncodeBuffer&)msgBuf).byteAlign();
      return stat;
   }
   else if (msgBuf.isA (OSRTMessageBufferIF::JSONEncode)) {
      return asn1JsonEnc_CoreCPID (msgBuf.getCtxtPtr(), &msgData);
   }
   return RTERR_NOTSUPP;
}

int ASN1C_CoreCPID::DecodeFrom (OSRTMessageBufferIF& msgBuf, OSBOOL free)
{
   int stat = setMsgBuf (msgBuf, TRUE);
   if (stat != 0) return (stat);

   asn1Init_CoreCPID (&msgData, free, getCtxtPtr());
   msgData.setContext (msgBuf.getContext());
   if (msgBuf.isA (OSRTMessageBufferIF::PERDecode)) {
      stat = asn1PD_CoreCPID (msgBuf.getCtxtPtr(), &msgData);
      ((ASN1PERDecodeBuffer&)msgBuf).byteAlign();
      return stat;
   }
   else if (msgBuf.isA (OSRTMessageBufferIF::JSONDecode)) {
      return asn1JsonDec_CoreCPID (msgBuf.getCtxtPtr(), &msgData);
   }
   return RTERR_NOTSUPP;
}

int asn1Init_CoreCPID (ASN1T_CoreCPID* pvalue, OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   if (free) {
      asn1Free_CoreCPID (pctxt, pvalue);
   }
   else {
      pvalue->t = 0;
      OSCRTLMEMSET (&pvalue->u, 0, sizeof(pvalue->u));
   }
   return 0;
}

void asn1Free_CoreCPID (OSCTXT *pctxt, ASN1T_CoreCPID* pvalue)
{
   if (0 == pvalue) return;
   switch (pvalue->t) {
      case 0: break; /* no choice; nothing to free */
      case 1:
         if (0 != pvalue->u.fiveGC) {
            asn1Free_GUAMI (pctxt, pvalue->u.fiveGC);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.fiveGC);
            pvalue->u.fiveGC = 0;
         }
         break;

      case 2:
         if (0 != pvalue->u.ePC) {
            asn1Free_GUMMEI (pctxt, pvalue->u.ePC);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.ePC);
            pvalue->u.ePC = 0;
         }
         break;

      default:
         if (0 != pvalue->u.extElem1) {
            if (!rtxCtxtTestFlag (pctxt, ASN1FASTCOPY)) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1->data);
               pvalue->u.extElem1->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1);
            pvalue->u.extElem1 = 0;
         }
   }
}

void ASN1C_CoreCPID::MemFree ()
{
   asn1Free_CoreCPID (getCtxtPtr(), &msgData);
}

