ASN1T_NRFrequencyBandItem* ASN1C_NRFrequencyBand_List::NewElement ()
{
   void* pdata = memAlloc (sizeof(ASN1T_NRFrequencyBandItem));

   if (0 == pdata) return 0;
   else return new (pdata) ASN1T_NRFrequencyBandItem;
}

ASN1T_NRFrequencyBandItem* ASN1C_NRFrequencyBand_List::AppendNewElement ()
{
   ASN1T_NRFrequencyBandItem* pdata = NewElement();
   if (0 != pdata) {
      Append (pdata);
   }
   return pdata;
}

int asn1Init_NRFrequencyBand_List (ASN1T_NRFrequencyBand_List* pvalue, 
   OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   rtxDListFastInit (pvalue);
   return 0;
}

void asn1Free_NRFrequencyBand_List (OSCTXT *pctxt, 
   ASN1T_NRFrequencyBand_List* pvalue)
{
   if (0 == pvalue) return;
   { ASN1T_NRFrequencyBandItem* pdata;
   OSRTDListNode* pnode = pvalue->head;
   while (0 != pnode) {
      pdata = (ASN1T_NRFrequencyBandItem*)pnode->data;
      asn1Free_NRFrequencyBandItem (pctxt, pdata);
      pnode = pnode->next;
   }
   rtxDListFreeAll (pctxt, pvalue);
   }
}

/* ASN1T_NRFrequencyInfo */

ASN1T_NRFrequencyInfo* new_ASN1T_NRFrequencyInfo (ASN1CType& ccobj)
{
   void* pdata = ccobj.memAlloc (sizeof(ASN1T_NRFrequencyInfo));
   if (0 == pdata) return 0;
   else return new (pdata) ASN1T_NRFrequencyInfo;
}

ASN1T_NRFrequencyInfo::ASN1T_NRFrequencyInfo ()
{
   m.frequencyShift7p5khzPresent = 0;
}

int asn1Init_NRFrequencyInfo (ASN1T_NRFrequencyInfo* pvalue, 
   OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   OSCRTLMEMSET (&pvalue->m, 0, sizeof (pvalue->m));
   asn1Init_NR_ARFCN (&pvalue->nrARFCN, free, pctxt);
   asn1Init_NRFrequencyBand_List (&pvalue->frequencyBand_List, free, pctxt);
   rtxDListFastInit (&pvalue->extElem1);
   return 0;
}

void asn1Free_NRFrequencyInfo (OSCTXT *pctxt, ASN1T_NRFrequencyInfo* pvalue)
{
   if (0 == pvalue) return;
   asn1Free_NR_ARFCN (pctxt, &pvalue->nrARFCN);
   asn1Free_NRFrequencyBand_List (pctxt, &pvalue->frequencyBand_List);
   rtxMemFreeOpenSeqExt (pctxt, &pvalue->extElem1);
}

